def check_files(files: List[str]) -> List[str]:
    files = [
        f for f in files if not f.startswith("http://")
    ]  # exclude online files, http
    files = [
        f for f in files if not f.startswith("https://")
    ]  # exclude online files, https
    missing_files = [file for file in files if not os.path.exists(file)]
    return missing_files


def _create_translator(service: str, lang_in: str, lang_out: str, envs: Dict = None, prompt=None, ignore_cache: bool = False):
    """创建翻译器实例（用于独立管线）"""
    from pdf2zh.translator import (
        GoogleTranslator, BingTranslator, DeepLTranslator, DeepLXTranslator,
        OllamaTranslator, XinferenceTranslator, AzureOpenAITranslator,
        OpenAITranslator, ZhipuTranslator, ModelScopeTranslator,
        SiliconTranslator, GeminiTranslator, AzureTranslator,
        TencentTranslator, DifyTranslator, AnythingLLMTranslator,
        ArgosTranslator, GrokTranslator, GroqTranslator,
        DeepseekTranslator, OpenAIlikedTranslator, QwenMtTranslator,
    )
    param = service.split(":", 1)
    service_name = param[0]
    service_model = param[1] if len(param) > 1 else None
    if not envs:
        envs = {}
    for translator_cls in [GoogleTranslator, BingTranslator, DeepLTranslator, DeepLXTranslator,
                           OllamaTranslator, XinferenceTranslator, AzureOpenAITranslator,
                           OpenAITranslator, ZhipuTranslator, ModelScopeTranslator,
                           SiliconTranslator, GeminiTranslator, AzureTranslator,
                           TencentTranslator, DifyTranslator, AnythingLLMTranslator,
                           ArgosTranslator, GrokTranslator, GroqTranslator,
                           DeepseekTranslator, OpenAIlikedTranslator, QwenMtTranslator]:
        if service_name == translator_cls.name:
            return translator_cls(lang_in, lang_out, service_model, envs=envs, prompt=prompt, ignore_cache=ignore_cache)
    return None


def _should_translate(text: str) -> bool:
    """判断单元格文本是否需要翻译（跳过纯数字、日期、编号等）"""
    if not text or not text.strip():
        return False
    t = text.strip()
    # 纯数字、日期、编号、单字符
    if len(t) <= 1:
        return False
    # 纯数字（含小数点、百分号、正负号）
    import re
    if re.match(r'^[+\-]?[\d.,\s%/:\-]+$', t):
        return False
    return True


def _fit_fontsize(rect, text: str, max_fontsize: float = 14, min_fontsize: float = 6) -> float:
    """基于单元格面积估算最佳字号，让 insert_textbox 自动换行"""
    w, h = rect.width - 2, rect.height - 2
    if w <= 0 or h <= 0:
        return min_fontsize

    # 估算文本总面积需求
    cjk = sum(1 for c in text if ord(c) > 0x2fff)
    latin = len(text) - cjk
    cell_area = w * h

    for size in [max_fontsize, 12, 11, 10, 9, 8, 7, min_fontsize]:
        # 每个字符占用面积 ≈ 宽 × 行高
        char_w_cjk = size * 1.0
        char_w_latin = size * 0.52
        line_height = size * 1.3
        text_total_w = cjk * char_w_cjk + latin * char_w_latin
        lines = max(1, text_total_w / w)
        needed_h = lines * line_height

        # 只要高度放得下就用这个字号
        if needed_h <= h + size * 0.5:  # 允许少量溢出
            return size
    return min_fontsize


def _is_cjk_text(text: str) -> bool:
    """判断文本是否以 CJK 字符为主"""
    cjk_count = sum(1 for c in text if '\u4e00' <= c <= '\u9fff' or '\u3000' <= c <= '\u30ff' or '\uac00' <= c <= '\ud7af')
    alpha_count = sum(1 for c in text if c.isalpha())
    return cjk_count > alpha_count * 0.3 if alpha_count > 0 else cjk_count > 0


def _insert_translated_text(page, rect, translated, max_fontsize=12):
    """在页面上白底覆盖 + 插入自适应字号的译文"""
    page.draw_rect(rect, color=None, fill=(1, 1, 1))
    fontsize = _fit_fontsize(rect, translated, max_fontsize=max_fontsize)
    # CJK 文本用 china-ss，拉丁文本用 helv（比例字体，间距正常）
    fontname = "china-ss" if _is_cjk_text(translated) else "helv"
    try:
        rc = page.insert_textbox(rect, translated, fontsize=fontsize, fontname=fontname, align=fitz.TEXT_ALIGN_LEFT)
    except Exception:
        fontname = "helv"
        rc = page.insert_textbox(rect, translated, fontsize=fontsize, fontname=fontname, align=fitz.TEXT_ALIGN_LEFT)
    # rc < 0 表示文本没放完（溢出），用更小字号重试
    if rc < 0 and fontsize > 6:
        page.draw_rect(rect, color=None, fill=(1, 1, 1))  # 重新覆盖
        page.insert_textbox(rect, translated, fontsize=6, fontname=fontname, align=fitz.TEXT_ALIGN_LEFT)


def _postprocess_tables(doc_zh: Document, translator, pages=None, callback=None, doc_original=None):
    """独立表格翻译管线：从原始文档提取表格文字 → 翻译 → 在译文文档上白底覆盖+插入"""
    # 从原始文档提取文字（主管线会删除文字操作符），在 doc_zh 上写入
    src_doc = doc_original if doc_original else doc_zh
    page_range = range(doc_zh.page_count) if pages is None else pages
    page_list = list(page_range)
    total = len(page_list)

    for idx, page_num in enumerate(page_list):
        if page_num >= doc_zh.page_count or page_num >= src_doc.page_count:
            continue
        if callback:
            class _P:
                def __init__(self, n, total, desc): self.n, self.total, self.desc = n, total, desc
            callback(_P(idx + 1, total, f"表格翻译: 第 {idx+1}/{total} 页"))

        src_page = src_doc[page_num]
        dst_page = doc_zh[page_num]
        try:
            tables = src_page.find_tables()
        except Exception:
            continue
        if not tables.tables:
            continue

        translated_count = 0
        for table in tables.tables:
            for cell in table.cells:
                if cell is None:
                    continue
                x0, y0, x1, y1 = cell[:4]
                if (x1 - x0) < 5 or (y1 - y0) < 5:
                    continue
                cell_rect = fitz.Rect(x0, y0, x1, y1)
                cell_text = src_page.get_text("text", clip=cell_rect).strip()
                if not _should_translate(cell_text):
                    continue

                try:
                    translated = translator.translate(cell_text)
                except Exception as e:
                    logger.warning(f"Table cell translate failed for '{cell_text[:30]}': {e}")
                    continue
                if not translated or not translated.strip():
                    continue
                translated = translated.strip()
                if translated == cell_text:
                    continue

                inner = fitz.Rect(x0 + 1, y0 + 1, x1 - 1, y1 - 1)
                # 参考原文字号：用原始文档提取该区域的 span 字号
                src_spans = src_page.get_text("dict", clip=cell_rect)["blocks"]
                ref_size = 10  # 默认参考字号
                for blk in src_spans:
                    if blk.get("type") != 0:
                        continue
                    for ln in blk.get("lines", []):
                        for sp in ln.get("spans", []):
                            ref_size = max(ref_size, sp.get("size", 10))
                _insert_translated_text(dst_page, inner, translated, max_fontsize=min(ref_size, 14))
                translated_count += 1
        logger.info(f"Page {page_num}: translated {translated_count} table cells")


def _postprocess_figures(doc_zh: Document, translator, pages=None, callback=None, doc_original=None):
    """独立图注翻译管线：从原始文档提取图注文字 → 翻译 → 在译文文档上白底覆盖+插入"""
    src_doc = doc_original if doc_original else doc_zh
    page_range = range(doc_zh.page_count) if pages is None else pages
    page_list = list(page_range)
    total = len(page_list)

    for idx, page_num in enumerate(page_list):
        if page_num >= doc_zh.page_count or page_num >= src_doc.page_count:
            continue
        if callback:
            class _P:
                def __init__(self, n, total, desc): self.n, self.total, self.desc = n, total, desc
            callback(_P(idx + 1, total, f"图注翻译: 第 {idx+1}/{total} 页"))

        src_page = src_doc[page_num]
        dst_page = doc_zh[page_num]

        blocks = src_page.get_text("dict", flags=fitz.TEXT_PRESERVE_WHITESPACE)["blocks"]
        translated_count = 0
        for block in blocks:
            if block["type"] != 0:
                continue
            for line in block["lines"]:
                line_text = ""
                line_rect = fitz.Rect()
                max_size = 0
                for span in line["spans"]:
                    line_text += span["text"]
                    line_rect |= fitz.Rect(span["bbox"])
                    max_size = max(max_size, span["size"])

                line_text = line_text.strip()
                if not _should_translate(line_text):
                    continue

                # 精确检查：doc_zh 在该位置是否还有文字（有=主管线已处理，跳过）
                zh_text = dst_page.get_text("text", clip=line_rect).strip()
                if zh_text:
                    continue

                try:
                    translated = translator.translate(line_text)
                except Exception as e:
                    logger.warning(f"Figure text translate failed for '{line_text[:30]}': {e}")
                    continue
                if not translated or not translated.strip():
                    continue
                translated = translated.strip()
                if translated == line_text:
                    continue

                _insert_translated_text(dst_page, line_rect, translated, max_fontsize=max_size)
                translated_count += 1
        logger.info(f"Page {page_num}: translated {translated_count} figure text items")


def _ocr_preprocess(stream: bytes, lang_in: str = "") -> bytes:
    """对纯图片扫描 PDF 进行 OCR，添加不可见文字层"""
    try:
        from rapidocr_onnxruntime import RapidOCR
    except Exception:
        logger.warning("RapidOCR not available, skipping OCR preprocessing")
        return stream

    try:
        ocr = RapidOCR()
        doc = Document(stream=stream)
        modified = False

        for page_num in range(doc.page_count):
            page = doc[page_num]
            # 检查页面是否有文字
            if page.get_text().strip():
                continue  # 已有文字层，跳过

            # 渲染页面为图片
            pix = page.get_pixmap(dpi=300)
            img_data = pix.tobytes("png")

            # OCR 识别
            result, _ = ocr(img_data)
            if not result:
                continue

            # 将 OCR 结果写入页面（不可见文字层）
            scale_x = page.rect.width / pix.width
            scale_y = page.rect.height / pix.height
            for line in result:
                box, text, confidence = line
                if confidence < 0.5:
                    continue
                # box 是 4 个点的坐标 [[x1,y1],[x2,y2],[x3,y3],[x4,y4]]
                x0 = min(p[0] for p in box) * scale_x
                y0 = min(p[1] for p in box) * scale_y
                x1 = max(p[0] for p in box) * scale_x
                y1 = max(p[1] for p in box) * scale_y
                font_size = (y1 - y0) * 0.8
                if font_size < 1:
                    font_size = 8
                # 插入不可见文字（透明色）
                rc = fitz.Rect(x0, y0, x1, y1)
                page.insert_textbox(
                    rc, text, fontsize=font_size,
                    fontname="helv", color=(0, 0, 0),
                    render_mode=3,  # 3 = invisible
                )
                modified = True

        if modified:
            buf = io.BytesIO()
            doc.save(buf)
            return buf.getvalue()
    except Exception as e:
        logger.warning(f"OCR preprocessing failed: {e}, continuing without OCR")
    return stream


def translate_patch(
    inf: BinaryIO,
    pages: Optional[list[int]] = None,
    vfont: str = "",
    vchar: str = "",
    thread: int = 0,
    doc_zh: Document = None,
    lang_in: str = "",
    lang_out: str = "",
    service: str = "",
    noto_name: str = "",
    noto: Font = None,
    callback: object = None,
    cancellation_event: asyncio.Event = None,
    model = None,  # 改为 None，避免类型注解导入 OnnxModel
    envs: Dict = None,
    prompt: Template = None,
    ignore_cache: bool = False,
    scan_mode: bool = False,
    translate_tables: bool = False,
    translate_figures: bool = False,
    ocr_mode: bool = False,
    glossary: dict = None,
    **kwarg: Any,
) -> None:
    # 延迟导入 TranslateConverter 和 OnnxModel
    from pdf2zh.converter import TranslateConverter
    try:
        from pdf2zh.doclayout import OnnxModel
    except (ImportError, OSError) as e:
        logger.warning(f"Failed to import OnnxModel: {e}")
        OnnxModel = None

    rsrcmgr = PDFResourceManager()
    layout = {}
    device = TranslateConverter(
        rsrcmgr,
        vfont,
        vchar,
        thread,
        layout,
        lang_in,
        lang_out,
        service,
        noto_name,
        noto,
        envs,
        prompt,
        ignore_cache,
        scan_mode,
    )

    assert device is not None
    obj_patch = {}
    interpreter = PDFPageInterpreterEx(rsrcmgr, device, obj_patch)
    if pages:
        total_pages = len(pages)
    else:
        total_pages = doc_zh.page_count

    parser = PDFParser(inf)
    doc = PDFDocument(parser)
    with tqdm.tqdm(total=total_pages) as progress:
        for pageno, page in enumerate(PDFPage.create_pages(doc)):
            if cancellation_event and cancellation_event.is_set():
                raise CancelledError("task cancelled")
            if pages and (pageno not in pages):
                continue
            progress.update()
            if callback:
                callback(progress)
            page.pageno = pageno
            pix = doc_zh[page.pageno].get_pixmap()
            image = np.frombuffer(pix.samples, np.uint8).reshape(
                pix.height, pix.width, 3
            )[:, :, ::-1]

            # 只有当 model 可用时才进行布局检测
            if model is not None:
                page_layout = model.predict(image, imgsz=int(pix.height / 32) * 32)[0]
                # kdtree 是不可能 kdtree 的，不如直接渲染成图片，用空间换时间
                box = np.ones((pix.height, pix.width))
                h, w = box.shape
                vcls = ["abandon", "figure", "table", "isolate_formula", "formula_caption"]
                for i, d in enumerate(page_layout.boxes):
                    if page_layout.names[int(d.cls)] not in vcls:
                        x0, y0, x1, y1 = d.xyxy.squeeze()
                        x0, y0, x1, y1 = (
                            np.clip(int(x0 - 1), 0, w - 1),
                            np.clip(int(h - y1 - 1), 0, h - 1),
                            np.clip(int(x1 + 1), 0, w - 1),
                            np.clip(int(h - y0 + 1), 0, h - 1),
                        )
                        box[y0:y1, x0:x1] = i + 2
                for i, d in enumerate(page_layout.boxes):
                    if page_layout.names[int(d.cls)] in vcls:
                        x0, y0, x1, y1 = d.xyxy.squeeze()
                        x0, y0, x1, y1 = (
                            np.clip(int(x0 - 1), 0, w - 1),
                            np.clip(int(h - y1 - 1), 0, h - 1),
                            np.clip(int(x1 + 1), 0, w - 1),
                            np.clip(int(h - y0 + 1), 0, h - 1),
                        )
                        box[y0:y1, x0:x1] = 0
                layout[page.pageno] = box
            else:
                logger.warning("Model not available, skipping layout detection")
                layout[page.pageno] = np.ones((pix.height, pix.width))
            # 新建一个 xref 存放新指令流
            page.page_xref = doc_zh.get_new_xref()  # hack 插入页面的新 xref
            doc_zh.update_object(page.page_xref, "<<>>")
            doc_zh.update_stream(page.page_xref, b"")
            doc_zh[page.pageno].set_contents(page.page_xref)
            interpreter.process_page(page)

    device.close()
    return obj_patch


def translate_stream(
    stream: bytes,
    pages: Optional[list[int]] = None,
    lang_in: str = "",
    lang_out: str = "",
    service: str = "",
    thread: int = 0,
    vfont: str = "",
    vchar: str = "",
    callback: object = None,
    cancellation_event: asyncio.Event = None,
    model = None,  # 避免类型注解导入 OnnxModel
    envs: Dict = None,
    prompt: Template = None,
    skip_subset_fonts: bool = False,
    ignore_cache: bool = False,
    scan_mode: bool = False,
    translate_tables: bool = False,
    translate_figures: bool = False,
    ocr_mode: bool = False,
    glossary: dict = None,
    **kwarg: Any,
):
    # 术语库注入 prompt
    if glossary and prompt:
        glossary_text = "\n".join(f"{k} -> {v}" for k, v in glossary.items())
        prompt_str = prompt.template if hasattr(prompt, 'template') else str(prompt)
        prompt = Template(
            f"IMPORTANT: Use the following terminology mapping when translating:\n{glossary_text}\n\n{prompt_str}"
        )
    elif glossary and not prompt:
        glossary_text = "\n".join(f"{k} -> {v}" for k, v in glossary.items())
        prompt = Template(
            f"IMPORTANT: Use the following terminology mapping when translating:\n{glossary_text}\n\n"
            f"Translate the following text from $lang_in to $lang_out:\n$text"
        )

    font_list = [("tiro", None)]

    font_path = download_remote_fonts(lang_out.lower())
    noto_name = NOTO_NAME

    # 只有当字体路径有效时才添加字体
    if font_path is not None:
        try:
            noto = Font(noto_name, font_path)
            font_list.append((noto_name, font_path))
        except Exception as e:
            logger.warning(f"Failed to load font {noto_name}: {e}")
    else:
        logger.warning(f"Font path is None, skipping font loading")

    # OCR 预处理：对纯图片扫描件添加文字层
    if ocr_mode:
        stream = _ocr_preprocess(stream, lang_in)

    doc_en = Document(stream=stream)
    stream = io.BytesIO()
    doc_en.save(stream)
    doc_zh = Document(stream=stream)
    page_count = doc_zh.page_count
    # font_list = [("GoNotoKurrent-Regular.ttf", font_path), ("tiro", None)]
    font_id = {}
    for page in doc_zh:
        for font in font_list:
            font_id[font[0]] = page.insert_font(font[0], font[1])
    xreflen = doc_zh.xref_length()
    for xref in range(1, xreflen):
        for label in ["Resources/", ""]:  # 可能是基于 xobj 的 res
            try:  # xref 读写可能出错
                font_res = doc_zh.xref_get_key(xref, f"{label}Font")
                target_key_prefix = f"{label}Font/"
                if font_res[0] == "xref":
                    resource_xref_id = re.search("(\\d+) 0 R", font_res[1]).group(1)
                    xref = int(resource_xref_id)
                    font_res = ("dict", doc_zh.xref_object(xref))
                    target_key_prefix = ""

                if font_res[0] == "dict":
                    for font in font_list:
                        target_key = f"{target_key_prefix}{font[0]}"
                        font_exist = doc_zh.xref_get_key(xref, target_key)
                        if font_exist[0] == "null":
                            doc_zh.xref_set_key(
                                xref,
                                target_key,
                                f"{font_id[font[0]]} 0 R",
                            )
            except Exception:
                pass

    fp = io.BytesIO()

    doc_zh.save(fp)
    obj_patch: dict = translate_patch(fp, **locals())

    for obj_id, ops_new in obj_patch.items():
        doc_zh.update_stream(obj_id, ops_new.encode())

    # === 独立后处理管线（表格/图注翻译） ===
    # 从原始文档(doc_en)提取文字，在翻译文档(doc_zh)上写入
    if translate_tables or translate_figures:
        try:
            _translator = _create_translator(service, lang_in, lang_out, envs, prompt, ignore_cache)
            if _translator:
                if translate_tables:
                    logger.info("Running independent table translation pipeline...")
                    _postprocess_tables(doc_zh, _translator, pages, callback, doc_original=doc_en)
                if translate_figures:
                    logger.info("Running independent figure translation pipeline...")
                    _postprocess_figures(doc_zh, _translator, pages, callback, doc_original=doc_en)
            else:
                logger.warning("Failed to create translator for post-processing")
        except Exception as e:
            logger.warning(f"Post-processing pipeline failed: {e}")

    doc_en.insert_file(doc_zh)
    for id in range(page_count):
        doc_en.move_page(page_count + id, id * 2 + 1)
    if not skip_subset_fonts:
        try:
            doc_zh.subset_fonts(fallback=True)
            doc_en.subset_fonts(fallback=True)
        except ValueError:
            log.warning("subset_fonts failed (font table issue), skipping")
    return (
        doc_zh.write(deflate=True, garbage=3, use_objstms=1),
        doc_en.write(deflate=True, garbage=3, use_objstms=1),
    )


def convert_to_pdfa(input_path, output_path):
    """
    Convert PDF to PDF/A format

    Args:
        input_path: Path to source PDF file
        output_path: Path to save PDF/A file
    """
    from pikepdf import Dictionary, Name, Pdf

    # Open the PDF file
    pdf = Pdf.open(input_path)

    # Add PDF/A conformance metadata
    metadata = {
        "pdfa_part": "2",
        "pdfa_conformance": "B",
        "title": pdf.docinfo.get("/Title", ""),
        "author": pdf.docinfo.get("/Author", ""),
        "creator": "PDF Math Translate",
    }

    with pdf.open_metadata() as meta:
        meta.load_from_docinfo(pdf.docinfo)
        meta["pdfaid:part"] = metadata["pdfa_part"]
        meta["pdfaid:conformance"] = metadata["pdfa_conformance"]

    # Create OutputIntent dictionary
    output_intent = Dictionary(
        {
            "/Type": Name("/OutputIntent"),
            "/S": Name("/GTS_PDFA1"),
            "/OutputConditionIdentifier": "sRGB IEC61966-2.1",
            "/RegistryName": "http://www.color.org",
            "/Info": "sRGB IEC61966-2.1",
        }
    )

    # Add output intent to PDF root
    if "/OutputIntents" not in pdf.Root:
        pdf.Root.OutputIntents = [output_intent]
    else:
        pdf.Root.OutputIntents.append(output_intent)

    # Save as PDF/A
    pdf.save(output_path, linearize=True)
    pdf.close()


def translate(
    files: list[str],
    output: str = "",
    pages: Optional[list[int]] = None,
    lang_in: str = "",
    lang_out: str = "",
    service: str = "",
    thread: int = 0,
    vfont: str = "",
    vchar: str = "",
    callback: object = None,
    compatible: bool = False,
    cancellation_event: asyncio.Event = None,
    model = None,  # 避免类型注解导入 OnnxModel
    envs: Dict = None,
    prompt: Template = None,
    skip_subset_fonts: bool = False,
    ignore_cache: bool = False,
    scan_mode: bool = False,
    translate_tables: bool = False,
    translate_figures: bool = False,
    ocr_mode: bool = False,
    glossary: dict = None,
    **kwarg: Any,
):
    if not files:
        raise PDFValueError("No files to process.")

    missing_files = check_files(files)

    if missing_files:
        print("The following files do not exist:", file=sys.stderr)
        for file in missing_files:
            print(f"  {file}", file=sys.stderr)
        raise PDFValueError("Some files do not exist.")

    result_files = []

    for file in files:
        if type(file) is str and (
            file.startswith("http://") or file.startswith("https://")
        ):
            print("Online files detected, downloading...")
            try:
                r = requests.get(file, allow_redirects=True)
                if r.status_code == 200:
                    with tempfile.NamedTemporaryFile(
                        suffix=".pdf", delete=False
                    ) as tmp_file:
                        print(f"Writing the file: {file}...")
                        tmp_file.write(r.content)
                        file = tmp_file.name
                else:
                    r.raise_for_status()
            except Exception as e:
                raise PDFValueError(
                    f"Errors occur in downloading the PDF file. Please check the link(s).\nError:\n{e}"
                )
        filename = os.path.splitext(os.path.basename(file))[0]

        # If the commandline has specified converting to PDF/A format
        # --compatible / -cp
        if compatible:
            with tempfile.NamedTemporaryFile(
                suffix="-pdfa.pdf", delete=False
            ) as tmp_pdfa:
                print(f"Converting {file} to PDF/A format...")
                convert_to_pdfa(file, tmp_pdfa.name)
                doc_raw = open(tmp_pdfa.name, "rb")
                os.unlink(tmp_pdfa.name)
        else:
            doc_raw = open(file, "rb")
        s_raw = doc_raw.read()
        doc_raw.close()

        temp_dir = Path(tempfile.gettempdir())
        file_path = Path(file)
        try:
            if file_path.exists() and file_path.resolve().is_relative_to(
                temp_dir.resolve()
            ):
                file_path.unlink(missing_ok=True)
                logger.debug(f"Cleaned temp file: {file_path}")
        except Exception as e:
            logger.warning(f"Failed to clean temp file {file_path}", exc_info=True)

        s_mono, s_dual = translate_stream(
            s_raw,
            **locals(),
        )
        file_mono = Path(output) / f"{filename}-mono.pdf"
        file_dual = Path(output) / f"{filename}-dual.pdf"
        doc_mono = open(file_mono, "wb")
        doc_dual = open(file_dual, "wb")
        doc_mono.write(s_mono)
        doc_dual.write(s_dual)
        doc_mono.close()
        doc_dual.close()
        result_files.append((str(file_mono), str(file_dual)))

    return result_files


def download_remote_fonts(lang: str):
    lang = lang.lower()
    LANG_NAME_MAP = {
        **{la: "GoNotoKurrent-Regular.ttf" for la in noto_list},
        **{
            la: f"SourceHanSerif{region}-Regular.ttf"
            for region, langs in {
                "CN": ["zh-cn", "zh-hans", "zh"],
                "TW": ["zh-tw", "zh-hant"],
                "JP": ["ja"],
                "KR": ["ko"],
            }.items()
            for la in langs
        },
    }
    font_name = LANG_NAME_MAP.get(lang, "GoNotoKurrent-Regular.ttf")

    # docker
    font_path = ConfigManager.get("NOTO_FONT_PATH", Path("/app", font_name).as_posix())
    if not Path(font_path).exists():
        result = get_font_and_metadata(font_name)
        if result is not None:
            font_path, _ = result
            font_path = font_path.as_posix()
        else:
            # 如果获取字体失败，使用默认字体
            logger.warning(f"无法获取字体 {font_name}，使用默认字体")
            font_path = None

    logger.info(f"use font: {font_path}")

    return font_path
